#include <bits/stdc++.h>
using namespace std;

int n;
vector<vector<pair<int,int>>> adj;

pair<long long,int> bfsFar(int start) {
    vector<long long> dist(n + 1, -1);
    queue<int> q;
    q.push(start);
    dist[start] = 0;
    int far = start;
    long long best = 0;
    while (!q.empty()) {
        int cur = q.front(); q.pop();
        for (auto& e : adj[cur]) {
            int nxt = e.first, w = e.second;
            if (dist[nxt] == -1) {
                dist[nxt] = dist[cur] + w;
                if (dist[nxt] > best) { best = dist[nxt]; far = nxt; }
                q.push(nxt);
            }
        }
    }
    return {best, far};
}

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    cin >> n;
    adj.assign(n + 1, {});
    for (int i = 0; i < n - 1; i++) {
        int u, v, w; cin >> u >> v >> w;
        adj[u].push_back({v, w});
        adj[v].push_back({u, w});
    }
    if (n <= 1) { cout << 0 << "\n"; return 0; }
    auto a = bfsFar(1);
    auto b = bfsFar(a.second);
    cout << b.first << "\n";
    return 0;
}
